{
  "name": "Low-Income Heating Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Maximum gross household income for 2025-2026 season (1 month / 3 months / 12 months): 1: $3,070/$9,209/$36,836; 2: $4,014/$12,043/$48,170; 3: $4,959/$14,876/$59,504; 4: $5,903/$17,710/$70,839; 5: $6,848/$20,543/$82,173; 6: $7,792/$23,377/$93,507; 7: $7,969/$23,908/$95,632; 8: $8,146/$24,439/$97,757; 9: $8,324/$24,971/$99,882; 10: $8,501/$25,502/$102,008. For >10 persons, contact Community Action Agency (CAA). Medical expenses may be deducted; TANF recipients automatically eligible at highest benefit level.[2][3][6]",
    "asset_limits": "No asset limits mentioned.[1][2]",
    "other_requirements": ["U.S. citizen, qualified alien, refugee, asylee, parolee for 1+ year, deportation withheld, or conditional entry (not asylum seekers or undocumented); mixed-status households eligible for eligible members.", "Proof of citizenship/residency.", "Household includes all at address sharing utility (even roommates).", "Proof of gross income (wages, SS, unemployment, pension, disability)."][2][4][6]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time payment to utility/fuel provider based on household size, income, fuel type, and factors like emergencies. Regular HEAP for heating costs; Crisis HEAP for emergencies (e.g., shutoff, broken heater). Exact max/min amounts not specified in sources; TANF recipients get highest benefit for size. Weatherization separate.[1][5][6]",
    "varies_by": "household_size|priority_tier"
  },
  "application": {
    "methods": ["Online via MaineHousing portal (starting 2024).", "In-person or phone at local CAP/CAA agency (many start July 1; contact for appointment).", "Phone examples: Community Concepts 800-866-5588; statewide help 1-800-452-4668.", "Mail not specified."],
    "processing_time": "Not specified; first-come first-served, funds limited.",
    "waitlist": "No waitlist mentioned; apply early as funding runs out and demand up 20%.[4]",
    "forms": ["No specific form name/number; applications via CAA or online."],
    "documents": ["Names, DOB, SSN, proof of citizenship for all household members.", "Unexpired photo ID of applicant.", "Proof of gross income last 30 days (or 12 months if requested): pay stubs, W2, 1099, SS statements, unemployment docs, etc.", "Proof of address (rent receipt, lease)."][2][4][5]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None",
    "regional_variations": "Administered by local Community Action Agencies (CAAs/CAPs) with potential differences in offices, appointment scheduling, wait times; contact local CAA.[2][4][5]",
    "offices_or_providers": ["Local CAAs/CAPs (e.g., Community Concepts); find via mainehousing.org or 1-800-452-4668."]
  },
  "official_source": "https://www.mainehousing.org/programs-services/energy/energydetails/liheap",
  "gotchas": ["Funding first-come first-served; apply early (fall/winter for heating, not year-round; many CAPs start July 1).", "Crisis only for emergencies (shutoff, broken heater).", "No cooling assistance in Maine.", "Household counts all at address on utility bill.", "Medical deductions possible if over income; TANF auto-eligible at max benefit.", "Apps incomplete without docs; respond fast to requests.", "Even if heat in rent, may apply.[1][4][5][6]"],
  "data_shape_notes": "Income table by household size and period (1/3/12 months); administered via regional CAAs with early application critical due to limited funds; medical deductions and TANF auto-max benefit unique qualifiers."
}

{
  "name": "Community Aging in Place Grant Program",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income at or below 100% of Area Median Income (AMI) for State CAIP; 80% AMI for owner-occupied primary residences in some contexts. Specific dollar amounts vary by location and household size (e.g., median income of recipients ~$18,000-$19,000; one source mentions < $40,000 but not confirmed as official limit). No full table provided in sources—check current AMI via MaineHousing.[1][2][5]",
    "asset_limits": "Not specified in program guidance; one non-official source mentions liquid assets below $50,000 (or $75,000 for couples) but this is unconfirmed for CAIP.[8]",
    "other_requirements": ["Homeowners or living in a home owned by a family member", "Primary residence with confirmed health and safety hazards", "Age 55+ or person with a disability resides there", "Live within service area of partner agency", "Owner-occupied for principal residence units[1][2][4][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "No-cost home safety checks, minor maintenance repairs, and accessibility modifications (e.g., smoke/CO detectors, dryer vents, furnace filters). Average grant limit $2,500-$3,000 per unit (State: ~$2,500-$3,000; Federal variant: $3,000).[1][2][4][5]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local partner agency (e.g., KVCAP for Kennebec/Somerset: (207) 859-1524, homeservices@kvcap.org)", "Application process via partner organizations administering the program for MaineHousing", "No central statewide phone/website/form specified; varies by partner[4][5]"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["Application process used by partners to determine eligibility (no specific form name/number listed)[1][4]"],
    "documents": ["Proof of income", "Proof of age/disability", "Proof of homeownership/occupancy", "Evidence of health/safety hazards (inferred from eligibility)[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must live within service area of partner agencies (e.g., Kennebec/Somerset via KVCAP); expanding to statewide but partner-dependent[2][5]",
    "regional_variations": "Administered by local non-profit partner organizations; different providers, service areas, and potentially wait times by region (e.g., 6 partners in 2018 serving 104 communities, 10 in 2019 serving 210)[2][4][5]",
    "offices_or_providers": ["KVCAP (Kennebec/Somerset Counties)", "Other MaineHousing partner agencies (list via MaineHousing RFQ process)[2][4][5]"]
  },
  "official_source": "https://mainehousing.org/docs/default-source/ehs-partners-library/elderly-home-modification-programs/program-guidance-brochures/program-guidance/community-aging-in-place-programs-guidance-01012023.pdf?sfvrsn=742d8115_2",
  "gotchas": ["Not directly available statewide—must contact specific partner agency for service area", "Distinguish State CAIP (age 55+, 100% AMI) from Federal variant (62+, 80% AMI, stricter owner rules)", "Funds only for homes with confirmed health/safety hazards", "Administered via local partners, not central MaineHousing intake", "Income based on AMI, which varies by county/household size—no fixed dollar table in sources[1][2][4][5]"],
  "data_shape_notes": "Administered regionally by partner non-profits with varying service areas; AMI-based income (varies by location/household); two variants (State/Federal) with age/income differences; no central application—partner dependent"
}

{
  "name": "State Health Insurance Assistance Program (SHIP) - Maine SHIP",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits. Services are free and available to all Medicare beneficiaries, older adults, and people with Medicare due to disability[4][3][6].",
    "asset_limits": "No asset limits or tests apply[4][6].",
    "other_requirements": ["Must be a Medicare beneficiary or expect to have Medicare soon; available to older people and those with Medicare due to disability; Maine resident implied by program scope[4][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential, one-on-one counseling including: information on Medicare (Parts A, B, Advantage, Part D), Medigap, MaineCare, preventive benefits, prescription drug coverage/options, Medicare Savings Programs enrollment help, medical bills/claims follow-up, supplemental policy comparisons, referrals to agencies (e.g., CMS, SSA, DHHS), programs to reduce out-of-pocket costs; provided by trained counselors who do not sell or recommend policies; delivered via phone, in-person, or Zoom[4][6][3][8]. No specific dollar amounts, hours per week, or tiers.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-800-262-2232 (statewide, hours 9AM-5PM Mon-Thu, 9AM-4PM Fri)[5][7][3]", "Website: https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/ship-medicare-assistance[4][5]", "In-person or Zoom: Through local Area Agencies on Aging, e.g., Southern Maine Agency on Aging at 207-396-6524[8]", "Regional providers: Five Area Agencies on Aging and Legal Services for Maine Elders[4]"],
    "processing_time": "No formal application or processing; services available immediately upon contact for counseling appointments[4][8].",
    "waitlist": null,
    "forms": ["No specific forms for SHIP counseling; for related Medicare Savings Programs, apply online via Maine DHHS or get assistance (no form number specified)[8][9]"],
    "documents": ["No documents required for counseling; for Medicare Savings Programs assistance, prepare income/asset details if pursuing enrollment[9][8]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered statewide through Office of Aging and Disability Services, five Area Agencies on Aging (e.g., Southern Maine Agency on Aging, Eastern Agency on Aging), and Legal Services for Maine Elders; local offices offer phone/Zoom/in-person with potentially varying contact numbers but same core services[4][8][9]. No noted differences in wait times or offerings by region.",
    "offices_or_providers": ["State office: 11 State House Station, Augusta ME 04333[5]", "Southern Maine Agency on Aging: 207-396-6524[8]", "Eastern Agency on Aging (implied contact via Medicare counseling)[9]"]
  },
  "official_source": "https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/ship-medicare-assistance[4]",
  "gotchas": ["Counselors do not sell insurance or recommend specific policies—purely informational and unbiased[4][8]", "Not a financial aid program itself; helps enroll in Medicare Savings Programs (MSP) or MaineCare which have income/asset limits (e.g., MSP: $1,183/month single, $10,000 assets; varies and separate application)[3][9]", "People may confuse with Medicaid/MaineCare or MSP—SHIP is counseling only, not direct benefits[4][6]", "For Medicare Savings Programs it assists with, eligibility finalized by DHHS with asset limits and no estate recovery[9]"],
  "data_shape_notes": "no income/asset test for counseling; free service for all Medicare-eligible; delivered via network of 5 Area Agencies on Aging; distinguishes from financial programs like MSP by providing enrollment assistance only"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income at or below 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are not specified in current sources; families must check current federal poverty guidelines via Maine Department of Labor or CareerCenter for precise figures (e.g., for 2026, consult official FPL tables).[2][4]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "Actively looking for work", "Priority given to veterans and qualified spouses, individuals over 65, those with disabilities, low literacy or limited English proficiency, rural residents, homeless or at-risk, low employment prospects, or prior American Job Center users"][2][4]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work-based training (average 20 hours per week) at nonprofits or public agencies (e.g., healthcare, office admin, food prep, customer service); paid at the highest of federal, state, or local minimum wage on a bi-weekly basis; training classes/workshops; access to CareerCenter employment services; transitional to unsubsidized jobs (positions are temporary).[1][4][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Visit Maine Department of Labor's Work Source Maine Virtual CareerCenter (https://www.myworksourcemaine.gov/resources/senior-community-service-employment-program-scsep-associates-training-development)", "Contact Area Agencies on Aging (AAAs) for information and referral (all five AAAs statewide)", "Call A4TD at (800) 439-3307 or visit https://www.a4td.org for orientations", "Attend online orientation webinars (e.g., via Zoom as scheduled)", "Maine DHHS OADS page: https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/scsep"][1][2][3],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not mentioned; may vary by provider or demand.",
    "forms": ["OADS SCSEP Participant Application (available via AAAs or providers like Allied Community Resources)"][8],
    "documents": ["Proof of age (e.g., ID)", "Proof of income (to verify ≤125% FPL)", "Proof of unemployment status", "Possibly Social Security number, residency proof; prepare household size details for income calculation (exact list confirmed during intake)"][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; applicable statewide.",
    "regional_variations": "Administered via five Area Agencies on Aging (AAAs), some providing training through community service assignments; providers like A4TD and possibly Allied Community Resources handle orientations and placements; wait times or host sites may differ by AAA region but no specific differences detailed.",
    "offices_or_providers": ["All five AAAs", "A4TD (https://www.a4td.org)", "Maine CareerCenters", "Work Source Maine Virtual CareerCenter"][1][2][3]
  },
  "official_source": "https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/scsep",
  "gotchas": ["Transitional/temporary positions only—not permanent jobs; must actively use CareerCenter services and seek unsubsidized employment; income limit is strict at 125% FPL (check current guidelines as they update yearly); priority tiers may delay non-priority applicants; no asset test but must prove unemployment and job search intent; funded partly by state/federal grants with limited slots (e.g., past funding ~$578k for Maine)."],
  "data_shape_notes": "Statewide via AAAs with priority enrollment tiers; income test at 125% FPL (varies by household size per federal guidelines); no fixed asset limits; temporary part-time training slots limited by grantee funding/providers."
}

{
  "name": "Maine Legal Services for the Elderly",
  "eligibility": {
    "age": 60,
    "income_limits": "Specific dollar amounts or tables not detailed in sources; prioritizes 'socially and economically needy' Maine residents age 60+, often at or below 200% of federal poverty guidelines based on similar programs, but determined case-by-case for legal services[2][5][6]",
    "asset_limits": "No asset limits specified; focus is on economic need rather than strict financial cutoffs[2][6]",
    "other_requirements": ["Maine resident", "Basic human needs at stake (e.g., MaineCare/Medicare issues, elder abuse, housing, public benefits)", "Non-criminal legal problems"]
  },
  "benefits": {
    "type": "service",
    "value": "Free confidential legal information, advice, and representation on issues including Medicare/MaineCare disputes, health coverage, elder abuse/protection orders, housing (eviction/foreclosure), consumer debt, public assistance benefits, guardianship, discharges, powers of attorney, health care advance directives, and Medicare Part D prescription drug assistance; attorneys in offices across the state for select representation cases[2][4][8]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Helpline 1-800-750-5353 (in-state) or 207-623-1797[2][4][5][8]", "Website: https://mainelse.org for information and Elder Rights Handbook[2][8]", "In-person: Attorneys located in offices across the state[4]"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["No specific application form required; call helpline for intake[2]"],
    "documents": ["Not explicitly listed; prepare details on legal issue, income, assets, and residency for case assessment"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Maine residents age 60+",
    "regional_variations": "Attorneys in offices across the state, but no specific wait time or service differences noted[4]",
    "offices_or_providers": ["Offices across Maine (specific locations not listed in sources)[4]"]
  },
  "official_source": "https://mainelse.org[8]",
  "gotchas": ["Not a general entitlement; services for when 'basic human needs are at stake' with priority triage—may get advice/referral only, not full representation[2][4]", "Avoid pre-printed powers of attorney forms from stores/internet as they may not be legal in Maine; consult LSE attorney instead[2]", "If ineligible, referrals to private attorneys at reduced fees[4]", "Focuses on non-criminal matters; not for all legal needs"],
  "data_shape_notes": "No strict income/asset tables or fixed benefits; eligibility based on age 60+, residency, economic/social need, and priority legal issues affecting basic needs; services tiered by case urgency with statewide helpline access but representation varies by office availability"
}
